ValueAndUnit _formatVelocity({
  required UnitType unitsType,
  double? mphValue,
  double? kmhValue,
}) {
  assert((mphValue == null) ^ (kmhValue == null));
  const kmToMileRatio = 0.621371;
  if (mphValue != null) {
    return switch (unitsType) {
      UnitType.mphInch => ValueAndUnit(mphValue.toStringAsFixed(1), "mph"),
      UnitType.kmhCm =>
        ValueAndUnit((mphValue / kmToMileRatio).toStringAsFixed(1), "km/h"),
    };
  } else {
    return switch (unitsType) {
      UnitType.mphInch =>
        ValueAndUnit((kmhValue! * kmToMileRatio).toStringAsFixed(1), "mph"),
      UnitType.kmhCm => ValueAndUnit(kmhValue!.toStringAsFixed(1), "km/h"),
    };
  }
}

ValueAndUnit _formatBreak({
  required UnitType unitsType,
  double? inchValue,
  double? cmValue,
}) {
  assert((inchValue == null) ^ (cmValue == null));
  const cmToInchRatio = 0.393701;
  if (inchValue != null) {
    return switch (unitsType) {
      UnitType.mphInch => ValueAndUnit(inchValue.toStringAsFixed(1), "in"),
      UnitType.kmhCm =>
        ValueAndUnit((inchValue / cmToInchRatio).toStringAsFixed(1), "cm"),
    };
  } else {
    return switch (unitsType) {
      UnitType.mphInch =>
        ValueAndUnit((cmValue! * cmToInchRatio).toStringAsFixed(1), "in"),
      UnitType.kmhCm => ValueAndUnit(cmValue!.toStringAsFixed(1), "cm"),

content.text:
現在の実装を確認しました。以下の3つのリファクタリングアプローチを提案します：

## リファクタリングアプローチの選択肢

### 1. メソッドを単純化（推奨）
言語判定をメソッド内で行い、生の値のみを受け取るように変更：

```dart
ValueAndUnit _formatBreak({
  required UnitType unitsType,
  required String language,
  required double value,
}) {
  final isEnglish = language == 'en';

  return switch ((unitsType, isEnglish)) {
    (UnitType.mphInch, true) => ValueAndUnit(value.toStringAsFixed(1), "in"),
    (UnitType.mphInch, false) => ValueAndUnit((value * 0.393701).toStringAsFixed(1), "in"),
    (UnitType.kmhCm, true) => ValueAndUnit((value / 0.393701).toStringAsFixed(1), "cm"),
    (UnitType.kmhCm, false) => ValueAndUnit(value.toStringAsFixed(1), "cm"),
  };
}
```

### 2. Hook化（Flutter Hooksアプローチ）
カスタムフックとして抽出：

```dart
// hooks/use_unit_formatter.dart
ValueAndUnit Function(double) useBreakFormatter() {
  final unitType = useRef(ref.watch(appUnitProvider));
  final language = useRef('en'); // context から取得

  return useCallback((double value) {
    return _formatBreak(
      unitsType: unitType.value,
      language: language.value,
      value: value,
    );
  }, [unitType.value, language.value]);
}
```

### 3. Extension Methods
より関数型プログラミングスタイル：

```dart
extension PitchStatsFormatter on double {
  ValueAndUnit asBreak(UnitType unitsType, String language) {
    // 実装
  }

  ValueAndUnit asVelocity(UnitType unitsType, String language) {
    // 実装  
  }
}
```

