   220→  );
   221→  if (verticalRange != null) {
   222→    items.add('${l10n.ball_details_page__vertical_break}: $verticalRange');
   223→  }
   224→
   225→  final horizontalRange = _formatBreakRange(
   226→    values: specs.horizontalBreak,
   227→    unitType: unitType,
   228→    isJapanese: isJapanese,
   229→  );
   230→  if (horizontalRange != null) {
   231→    items.add('${l10n.ball_details_page__horizontal_break}: $horizontalRange');
   232→  }
   233→
   234→  return items;
   235→}
   236→
   237→String? _formatVelocityRange({
   238→  required List<num> values,
   239→  required UnitType unitType,
   240→  required bool isJapanese,
   241→}) {
   242→  if (values.isEmpty) {
   243→    return null;
   244→  }
   245→  final sortedValues = values.map((e) => e.toDouble()).toList()..sort();
   246→  final formattedValues = sortedValues
   247→      .map((value) => UnitConverter.formatVelocity(value, unitType))
   248→      .toList();
   249→  if (formattedValues.isEmpty) {
   250→    return null;
   251→  }
   252→  final unit = formattedValues.first.unit;
   253→  if (formattedValues.length == 1) {
   254→    return unit.isEmpty
   255→        ? formattedValues.first.value
   256→        : '${formattedValues.first.value} $unit';
   257→  }
   258→  final separator = isJapanese ? '〜' : ' - ';
   259→  final rangeString =
   260→      '${formattedValues.first.value}$separator${formattedValues.last.value}';
   261→  return unit.isEmpty ? rangeString : '$rangeString $unit';
   262→}
   263→
   264→String? _formatBreakRange({
   265→  required List<num> values,
   266→  required UnitType unitType,
   267→  required bool isJapanese,
   268→}) {
   269→  if (values.isEmpty) {
   270→    return null;
   271→  }
   272→  final sortedValues = values.map((e) => e.toDouble()).toList()..sort();
   273→  final formattedValues = sortedValues
   274→      .map((value) => UnitConverter.formatBreak(value, unitType))
   275→      .toList();
   276→  if (formattedValues.isEmpty) {
   277→    return null;
   278→  }
   279→  final unit = formattedValues.first.unit;
   280→  if (formattedValues.length == 1) {
   281→    return unit.isEmpty
   282→        ? formattedValues.first.value
   283→        : '${formattedValues.first.value} $unit';
   284→  }
   285→  final separator = isJapanese ? '〜' : ' - ';
   286→  final rangeString =
   287→      '${formattedValues.first.value}$separator${formattedValues.last.value}';
   288→  return unit.isEmpty ? rangeString : '$rangeString $unit';
   289→}
