/// {@category Utils}
library;

// Project imports:
import 'package:baseball_detector_flutter/data/models/enums/unit_type.dart';

class ValueAndUnit {
  final String value;
  final String unit;
  const ValueAndUnit(this.value, this.unit);

  static const notAssigned = ValueAndUnit("N/a", "");
}

class UnitConverter {
  static ValueAndUnit formatEfficiency(double? efficiencyValue) {
    if (efficiencyValue == null || efficiencyValue.isNaN) {
      return ValueAndUnit.notAssigned;
    }
    return ValueAndUnit((efficiencyValue * 100).floor().toString(), "%");
  }

  static ValueAndUnit formatVelocity(double? kmphValue, UnitType unitsType) {
    if (kmphValue == null || kmphValue.isNaN) {
      return ValueAndUnit.notAssigned;
    }
    const kmToMileRatio = 0.621371;
    switch (unitsType) {
      case UnitType.mphInch:
        return ValueAndUnit(
            (kmphValue * kmToMileRatio).toStringAsFixed(1), "mph");
      case UnitType.kmhCm:
        return ValueAndUnit(kmphValue.toStringAsFixed(1), "km/h");
    }
  }

  static ValueAndUnit formatGyroDegree(double? valueGyroDegree) {
    if (valueGyroDegree == null || valueGyroDegree.isNaN) {
      return ValueAndUnit.notAssigned;
    }
    return ValueAndUnit((valueGyroDegree).floor().toString(), "°");
  }

  static double convertBreak(double value, UnitType unitsType) {
    const cmToInchRatio = 0.393701;
    switch (unitsType) {
      case UnitType.mphInch:
        return value * cmToInchRatio * 100;
      case UnitType.kmhCm:
        return value * 100;
    }
  }

  static ValueAndUnit formatBreak(double? value, UnitType unitsType) {
    if (value == null || value.isNaN) {
      return ValueAndUnit.notAssigned;
    }
    final converted = convertBreak(value, unitsType);
    switch (unitsType) {
      case UnitType.mphInch:
        return ValueAndUnit(converted.toStringAsFixed(1), "in");
      case UnitType.kmhCm:
        return ValueAndUnit(converted.toStringAsFixed(1), "cm");
    }
  }

  static ValueAndUnit formatSpinDirection(double? spinDirectionValue) {
    if (spinDirectionValue == null || spinDirectionValue.isNaN) {
      return ValueAndUnit.notAssigned;
    }
    final m = 12 * spinDirectionValue;
    final hour = m.floor().toString().padLeft(2, '0');
    final minute = (60 * (m - m.floor())).floor().toString().padLeft(2, '0');
    return ValueAndUnit("$hour:$minute", "");
  }

  static ValueAndUnit formatSpin(double? spinValue) {
    if (spinValue == null || spinValue.isNaN) {
      return ValueAndUnit.notAssigned;
    }
    return ValueAndUnit(spinValue.toStringAsFixed(0), "rpm");
  }

  static ValueAndUnit formatAngle(double? valueAngle) {
    if (valueAngle == null || valueAngle.isNaN) {
      return ValueAndUnit.notAssigned;
    }
    return ValueAndUnit(valueAngle.toStringAsFixed(1), "°");
  }

  /// Format velocity value with language-aware unit conversion
  ///
  /// [value]: The raw velocity value from server
  /// [unitType]: Target unit type preference
  /// [language]: Language code ("en" for English, others for local units)
  static ValueAndUnit formatVelocityWithLanguage({
    required double value,
    required UnitType unitType,
    required String language,
  }) {
    const kmToMileRatio = 0.621371;
    final isEnglish = language == 'en';

    return switch ((unitType, isEnglish)) {
      (UnitType.mphInch, true) => ValueAndUnit(value.toStringAsFixed(1), "mph"),
      (UnitType.mphInch, false) => ValueAndUnit((value * kmToMileRatio).toStringAsFixed(1), "mph"),
      (UnitType.kmhCm, true) => ValueAndUnit((value / kmToMileRatio).toStringAsFixed(1), "km/h"),
      (UnitType.kmhCm, false) => ValueAndUnit(value.toStringAsFixed(1), "km/h"),
    };
  }

  /// Format break value with language-aware unit conversion
  ///
  /// [value]: The raw break value from server
  /// [unitType]: Target unit type preference
  /// [language]: Language code ("en" for English, others for local units)
  static ValueAndUnit formatBreakWithLanguage({
    required double value,
    required UnitType unitType,
    required String language,
  }) {
    const cmToInchRatio = 0.393701;
    final isEnglish = language == 'en';

    return switch ((unitType, isEnglish)) {
      (UnitType.mphInch, true) => ValueAndUnit(value.toStringAsFixed(1), "in"),
      (UnitType.mphInch, false) => ValueAndUnit((value * cmToInchRatio).toStringAsFixed(1), "in"),
      (UnitType.kmhCm, true) => ValueAndUnit((value / cmToInchRatio).toStringAsFixed(1), "cm"),
      (UnitType.kmhCm, false) => ValueAndUnit(value.toStringAsFixed(1), "cm"),
    };
  }
}

