// Flutter imports:
import 'package:baseball_detector_flutter/data/models/ai_coach/ai_coach_report_params.dart';
import 'package:baseball_detector_flutter/data/models/enums/unit_type.dart';
import 'package:flutter/material.dart';

// Package imports:
import 'package:gap/gap.dart';
import 'package:hooks_riverpod/hooks_riverpod.dart';

// Project imports:
import 'package:baseball_detector_flutter/data/models/ai_coach/pitch_features.dart';
import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';
import 'package:baseball_detector_flutter/providers/app_unit_provider.dart';
import 'package:baseball_detector_flutter/utils/unit_converter.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/ai_coach_report/components/expansion_tile_card.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/ai_coach_report/components/pitch_type_chip.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/ai_coach_report/components/strategy_list.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/hooks/use_pitch_type_map.dart';

class PitchFeaturesExpansionTile extends HookConsumerWidget {
  const PitchFeaturesExpansionTile({
    required this.pitchFeatures,
    required this.params,
    this.titleStyle,
    super.key,
  });

  final PitchFeatures pitchFeatures;
  final AICoachReportParams params;
  final TextStyle? titleStyle;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final theme = Theme.of(context);
    final scheme = theme.colorScheme;
    final l10n = context.l10n;
    final pitches = pitchFeatures.pitches;
    final getPitchTypeColor = usePitchTypeColor();
    final translatePitchType = useTranslatePitchType();
    final unitType = ref.watch(appUnitProvider);

    final vUnit = UnitConverter.formatVelocityWithLanguage(value: 0, unitType: unitType, language: 'en').unit;
    final bUnit = UnitConverter.formatBreakWithLanguage(value: 0, unitType: unitType, language: 'en').unit;

    final effectiveTitleStyle = titleStyle ??
        theme.textTheme.titleMedium?.copyWith(
          fontWeight: FontWeight.w600,
          color: scheme.onSurface,
        );
    final tableHeaderStyle = theme.textTheme.bodySmall?.copyWith(
      fontWeight: FontWeight.w600,
      color: scheme.onSurfaceVariant,
    );
    final tableHeaderFontSize = tableHeaderStyle?.fontSize ?? 12;
    final tableUnitStyle = tableHeaderStyle?.copyWith(
      fontSize: tableHeaderFontSize - 1,
      fontWeight: FontWeight.w500,
      color: scheme.onSurfaceVariant.withValues(alpha: 0.7),
    );
    final tableValueStyle = theme.textTheme.bodyMedium?.copyWith(
      fontWeight: FontWeight.w500,
      color: scheme.onSurface,
    );
    final tablePitchNameStyle = theme.textTheme.bodySmall?.copyWith(
      fontWeight: FontWeight.w600,
      color: scheme.onSurface,
    );
    final detailLabelStyle = theme.textTheme.bodyMedium?.copyWith(
      color: scheme.onSurfaceVariant,
    );

    return ExpansionTileCard(
      titleBuilder: (icon) => Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Row(
            mainAxisAlignment: MainAxisAlignment.spaceBetween,
            children: [
              Text(
                l10n.ai_coach_report__pitch_features_title,
                style: effectiveTitleStyle,
              ),
              icon,
            ],
          ),
          const Gap(16),
          // 球種データテーブル（常時表示）
          Container(
            decoration: BoxDecoration(
              border: Border.all(color: scheme.outline.withValues(alpha: 0.3)),
              borderRadius: BorderRadius.circular(4),
            ),
            child: Column(
              children: [
                // ヘッダー行
                Container(
                  decoration: BoxDecoration(
                    color:
                        scheme.surfaceContainerHighest.withValues(alpha: 0.5),
                    borderRadius:
                        const BorderRadius.vertical(top: Radius.circular(4)),
                  ),
                  padding:
                      const EdgeInsets.symmetric(horizontal: 12, vertical: 10),
                  child: Row(
                    children: [
                      Expanded(
                        flex: 2,
                        child: Text(
                          l10n.ai_coach_report__pitch_type_column,
                          style: tableHeaderStyle,
                        ),
                      ),
                      Expanded(
                        flex: 1,
                        child: Column(
                          crossAxisAlignment: CrossAxisAlignment.end,
                          children: [
                            Text(
                              l10n.ai_coach_report__velocity_column,
                              style: tableHeaderStyle,
                            ),
                            Text(
                              '[$vUnit]',
                              style: tableUnitStyle,
                            ),
                          ],
                        ),
                      ),
                      Expanded(
                        flex: 1,
                        child: Column(
                          crossAxisAlignment: CrossAxisAlignment.end,
                          children: [
                            Text(
                              l10n.ai_coach_report__vertical_break_column,
                              style: tableHeaderStyle,
                            ),
                            Text(
                              '[$bUnit]',
                              style: tableUnitStyle,
                            ),
                          ],
                        ),
                      ),
                      Expanded(
                        flex: 1,
                        child: Column(
                          crossAxisAlignment: CrossAxisAlignment.end,
                          children: [
                            Text(
                              l10n.ai_coach_report__horizontal_break_column,
                              style: tableHeaderStyle,
                            ),
                            Text(
                              '[$bUnit]',
                              style: tableUnitStyle,
                            ),
                          ],
                        ),
                      ),
                    ],
                  ),
                ),
                // データ行
                ...pitches.map((pitch) {
                  final stats = pitch.stats;

                  final velo = UnitConverter.formatVelocityWithLanguage(
                    value: stats.initialVelocity,
                    unitType: unitType,
                    language: params.language,
                  );

                  final vb = UnitConverter.formatBreakWithLanguage(
                    value: stats.verticalBreak,
                    unitType: unitType,
                    language: params.language,
                  );

                  final hb = UnitConverter.formatBreakWithLanguage(
                    value: stats.horizontalBreak,
                    unitType: unitType,
                    language: params.language,
                  );

                  return Container(
                    decoration: BoxDecoration(
                      border: Border(
                        bottom: BorderSide(
                          color: scheme.outline.withValues(alpha: 0.2),
                          width: 0.5,
                        ),
                      ),
                    ),
                    padding: const EdgeInsets.symmetric(
                      horizontal: 12,
                      vertical: 10,
                    ),
                    child: Row(
                      children: [
                        Expanded(
                          flex: 2,
                          child: Row(
                            children: [
                              Container(
                                width: 8,
                                height: 8,
                                decoration: BoxDecoration(
                                  color: getPitchTypeColor(
                                      pitch.pitchType.pitchType),
                                  shape: BoxShape.circle,
                                ),
                              ),
                              const Gap(8),
                              Text(
                                translatePitchType(
                                  pitch.pitchType.pitchType,
                                ),
                                style: tablePitchNameStyle,
                                maxLines: 2,
                              ),
                            ],
                          ),
                        ),
                        Expanded(
                          flex: 1,
                          child: Text(
                            velo.value,
                            textAlign: TextAlign.right,
                            style: tableValueStyle,
                          ),
                        ),
                        Expanded(
                          flex: 1,
                          child: Text(
                            vb.value,
                            textAlign: TextAlign.right,
                            style: tableValueStyle,
                          ),
                        ),
                        Expanded(
                          flex: 1,
                          child: Text(
                            hb.value,
                            textAlign: TextAlign.right,
                            style: tableValueStyle,
                          ),
                        ),
                      ],
                    ),
                  );
                }),
              ],
            ),
          ),
        ],
      ),
      children: [
        for (var i = 0; i < pitches.length; i++)
          SizedBox(
            width: double.infinity,
            child: DecoratedBox(
              decoration: sectionContainerDecoration(scheme),
              child: Padding(
                padding: sectionContainerPadding,
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    PitchTypeChip(pitchType: pitches[i].pitchType),
                    const Gap(16),
                    Table(
                      columnWidths: const {
                        0: FlexColumnWidth(1),
                        1: FlexColumnWidth(1),
                        2: FlexColumnWidth(1),
                      },
                      children: [
                        TableRow(
                          children: [
                            Padding(
                              padding: const EdgeInsets.only(bottom: 4.0),
                              child: Text(
                                context.l10n.ai_coach_report__velocity_column,
                                style: tableHeaderStyle,
                              ),
                            ),
                            Padding(
                              padding: const EdgeInsets.only(bottom: 4.0),
                              child: Text(
                                context.l10n
                                    .ai_coach_report__vertical_break_column,
                                style: tableHeaderStyle,
                              ),
                            ),
                            Padding(
                              padding: const EdgeInsets.only(bottom: 4.0),
                              child: Text(
                                context.l10n
                                    .ai_coach_report__horizontal_break_column,
                                style: tableHeaderStyle,
                              ),
                            ),
                          ],
                        ),
                        TableRow(
                          children: [
                            Padding(
                              padding: const EdgeInsets.only(top: 4.0),
                              child: Text(
                                () {
                                  final stats = pitches[i].stats;
                                  final velo = UnitConverter.formatVelocityWithLanguage(
                                    value: stats.initialVelocity,
                                    unitType: unitType,
                                    language: params.language,
                                  );

                                  return '${velo.value} ${velo.unit}';
                                }(),
                                style: tableValueStyle,
                              ),
                            ),
                            Padding(
                              padding: const EdgeInsets.only(top: 4.0),
                              child: Text(
                                () {
                                  final stats = pitches[i].stats;
                                  final vb = UnitConverter.formatBreakWithLanguage(
                                    value: stats.verticalBreak,
                                    unitType: unitType,
                                    language: params.language,
                                  );

                                  return '${vb.value} ${vb.unit}';
                                }(),
                                style: tableValueStyle,
                              ),
                            ),
                            Padding(
                              padding: const EdgeInsets.only(top: 4.0),
                              child: Text(
                                () {
                                  final stats = pitches[i].stats;

                                  final hb = UnitConverter.formatBreakWithLanguage(
                                    value: stats.horizontalBreak,
                                    unitType: unitType,
                                    language: params.language,
                                  );

                                  return '${hb.value} ${hb.unit}';
                                }(),
                                style: tableValueStyle,
                              ),
                            ),
                          ],
                        ),
                      ],
                    ),
                    const Gap(8),
                    for (final note in pitches[i].notes)
                      Padding(
                        padding: const EdgeInsets.symmetric(vertical: 2),
                        child: Text(
                          '• $note',
                          style: detailLabelStyle,
                        ),
                      ),
                  ],
                ),
              ),
            ),
          ),
        // トンネル候補
        if (pitchFeatures.tunnelCandidates.goodTunnels.isNotEmpty) ...[
          Text(
            l10n.ai_coach_report__tunnel_candidates_title,
            style: titleStyle,
          ),
          const Gap(8),
          StrategyList(
            items: pitchFeatures.tunnelCandidates.goodTunnels
                .map((e) => (e.label, e.description))
                .toList(),
          ),
        ],
      ],
    );
  }

  ValueAndUnit _formatVelocity({
    required UnitType unitsType,
    required String language,
    required double value,
  }) {
    const kmToMileRatio = 0.621371;
    final isEnglish = language == 'en';

    return switch ((unitsType, isEnglish)) {
      (UnitType.mphInch, true) => ValueAndUnit(value.toStringAsFixed(1), "mph"),
      (UnitType.mphInch, false) => ValueAndUnit((value * kmToMileRatio).toStringAsFixed(1), "mph"),
      (UnitType.kmhCm, true) => ValueAndUnit((value / kmToMileRatio).toStringAsFixed(1), "km/h"),
      (UnitType.kmhCm, false) => ValueAndUnit(value.toStringAsFixed(1), "km/h"),
    };
  }

  ValueAndUnit _formatBreak({
    required UnitType unitsType,
    required String language,
    required double value,
  }) {
    const cmToInchRatio = 0.393701;
    final isEnglish = language == 'en';

    return switch ((unitsType, isEnglish)) {
      (UnitType.mphInch, true) => ValueAndUnit(value.toStringAsFixed(1), "in"),
      (UnitType.mphInch, false) => ValueAndUnit((value * cmToInchRatio).toStringAsFixed(1), "in"),
      (UnitType.kmhCm, true) => ValueAndUnit((value / cmToInchRatio).toStringAsFixed(1), "cm"),
      (UnitType.kmhCm, false) => ValueAndUnit(value.toStringAsFixed(1), "cm"),
      };
    }
  }
}

