      fontWeight: FontWeight.w600,
      color: scheme.onSurface,
    );
    final proposalDetailStyle = theme.textTheme.bodyMedium?.copyWith(
      color: scheme.onSurfaceVariant,
    );
    return ExpansionTileCard(
      titleBuilder: (icon) => Row(
        mainAxisAlignment: MainAxisAlignment.spaceBetween,
        children: [
          Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              Text(
                l10n.ai_coach_report__new_pitch_title,
                style: effectiveTitleStyle,
              ),
              const Gap(4),
              Text(
                l10n.ai_coach_report__new_pitch_subtitle(proposals.length),
                style: effectiveSubtitleStyle,
              ),
            ],
          ),
          icon,
        ],
      ),
      children: [
        SizedBox(
          width: double.infinity,
          child: DecoratedBox(
            decoration: sectionContainerDecoration(scheme),
            child: Padding(
              padding: sectionContainerPadding,
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  for (final p in proposals) ...[
                    PitchTypeChip(pitchType: p.pitchType),
                    const Gap(12),
                    ..._buildProposalSections(
                      proposal: p,
                      params: params,
                      l10n: l10n,
                      scheme: scheme,
                      sectionTitleStyle: proposalTitleStyle,
                      itemStyle: proposalDetailStyle,
                      unitType: unitType,
                    ),
                    const Gap(16),
                  ]
                ],
              ),
            ),
          ),
        ),
      ],
    );
  }
}

List<Widget> _buildProposalSections({
  required Proposal proposal,
  required AICoachReportParams params,
  required L10n l10n,
  required ColorScheme scheme,
  required TextStyle? sectionTitleStyle,
  required TextStyle? itemStyle,
  required UnitType unitType,
}) {
  final sections = <Widget>[];
  final isJapaneseLocale = params.language == 'ja';

  final reasonsSection = _buildBulletSection(
    title: l10n.ai_coach_report__new_pitch_reasons_heading,
    items: proposal.reasons,
    sectionTitleStyle: sectionTitleStyle,
    itemStyle: itemStyle,
    bulletColor: scheme.primary,
  );
  if (reasonsSection != null) {
    sections.add(reasonsSection);
  }

  final targetSpecItems = _buildTargetSpecItems(
    specs: proposal.targetSpecs,
    l10n: l10n,
    unitType: unitType,
    isJapanese: isJapaneseLocale,
  );
  final targetSpecSection = _buildBulletSection(
    title: l10n.ai_coach_report__new_pitch_target_specs_heading,
    items: targetSpecItems,
    sectionTitleStyle: sectionTitleStyle,
    itemStyle: itemStyle,
    bulletColor: scheme.primary,
  );
  if (targetSpecSection != null) {
    sections.add(targetSpecSection);
  }

  final expectedEffectsSection = _buildBulletSection(
    title: l10n.ai_coach_report__new_pitch_expected_effects_heading,
    items: proposal.expectedEffects,
    sectionTitleStyle: sectionTitleStyle,
    itemStyle: itemStyle,
    bulletColor: scheme.primary,
  );
  if (expectedEffectsSection != null) {
    sections.add(expectedEffectsSection);
  }

  final spacedSections = <Widget>[];
  for (var i = 0; i < sections.length; i++) {
    spacedSections.add(sections[i]);
    if (i != sections.length - 1) {
      spacedSections.add(const Gap(12));
    }
  }
  return spacedSections;
}

Widget? _buildBulletSection({
  required String title,
  required List<String> items,
  required TextStyle? sectionTitleStyle,
  required TextStyle? itemStyle,
  required Color bulletColor,
}) {
  if (items.isEmpty) {
    return null;
  }
  return Column(
    crossAxisAlignment: CrossAxisAlignment.start,
    children: [
      Text(title, style: sectionTitleStyle),
      const Gap(8),
      Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          for (var i = 0; i < items.length; i++)
            Padding(
              padding: EdgeInsets.only(bottom: i == items.length - 1 ? 0 : 8),
              child: Text(
                '• ${items[i]}',
                style: itemStyle,
              ),
            ),
        ],
      ),
    ],
  );
}

List<String> _buildTargetSpecItems({
  required TargetSpecs specs,
  required L10n l10n,
  required UnitType unitType,
  required bool isJapanese,
}) {
  final items = <String>[];

  final velocityRange = _formatVelocityRange(
    values: specs.initialVelocity,
    unitType: unitType,
    isJapanese: isJapanese,
  );
  if (velocityRange != null) {
    items.add('${l10n.ball_details_page__initial_velocity}: $velocityRange');
  }

  final verticalRange = _formatBreakRange(
    values: specs.verticalBreak,
    unitType: unitType,
    isJapanese: isJapanese,
  );
  if (verticalRange != null) {
    items.add('${l10n.ball_details_page__vertical_break}: $verticalRange');
  }

  final horizontalRange = _formatBreakRange(
    values: specs.horizontalBreak,
    unitType: unitType,
    isJapanese: isJapanese,
  );
  if (horizontalRange != null) {
    items.add('${l10n.ball_details_page__horizontal_break}: $horizontalRange');
  }

  return items;
}

String? _formatVelocityRange({
  required List<num> values,
  required UnitType unitType,
  required bool isJapanese,
}) {
  if (values.isEmpty) {
    return null;
  }
  final sortedValues = values.map((e) => e.toDouble()).toList()..sort();
  final formattedValues = sortedValues
      .map((value) => UnitConverter.formatVelocity(value, unitType))
      .toList();
  if (formattedValues.isEmpty) {
    return null;
  }
  final unit = formattedValues.first.unit;
  if (formattedValues.length == 1) {
    return unit.isEmpty
        ? formattedValues.first.value
        : '${formattedValues.first.value} $unit';
  }
  final separator = isJapanese ? '〜' : ' - ';
  final rangeString =
      '${formattedValues.first.value}$separator${formattedValues.last.value}';
  return unit.isEmpty ? rangeString : '$rangeString $unit';
}

String? _formatBreakRange({
  required List<num> values,
  required UnitType unitType,
  required bool isJapanese,
}) {
  if (values.isEmpty) {
    return null;
  }
  final sortedValues = values.map((e) => e.toDouble()).toList()..sort();
  final formattedValues = sortedValues
      .map((value) => UnitConverter.formatBreak(value, unitType))
      .toList();
  if (formattedValues.isEmpty) {
    return null;
  }
  final unit = formattedValues.first.unit;
  if (formattedValues.length == 1) {
    return unit.isEmpty
        ? formattedValues.first.value
        : '${formattedValues.first.value} $unit';
  }
  final separator = isJapanese ? '〜' : ' - ';
  final rangeString =
      '${formattedValues.first.value}$separator${formattedValues.last.value}';
  return unit.isEmpty ? rangeString : '$rangeString $unit';
}

